import struct
import shutil

data_strs = [
    '',
    '',
    '',
    '',
    '00002100430463048408A608A60CC70CE91009112A154404860CA610C814081D281D491D6A218608A70CC910EA100C15A708C908C90CE90CEA100A112C154C196D1D901D6404A508C60C071527194719471D67218825A829C82DE8310836293A63008404A60CC710E9100C115019741D981D007C007CE90C0C112F1550195319'
]

with open('D:/android/3sx/SF33RDAFS/1427_bg140.bin', 'rb') as f:
    orig = list(struct.unpack('<1088H', f.read(2176)))

final_palette = []
idx = 0

for s in data_strs:
    for i in range(0, len(s), 4):
        part = s[i:i+4]
        b0 = int(part[0:2], 16)
        b1 = int(part[2:4], 16)
        
        val = (b1 << 8) | b0
        b = (val >> 10) & 0x1F
        g = (val >> 5) & 0x1F
        r = val & 0x1F

        if idx % 64 == 0:
            final_palette.append(0x0000)
            idx += 1
            continue

        if b == 31 and g == 0 and r == 0:
            final_palette.append(orig[idx])
            idx += 1
            continue
            
        out_val = 0x8000 | (r << 10) | (g << 5) | b
        final_palette.append(out_val)
        idx += 1

print(f'Successfully decoded {len(final_palette)} colors.')

out_path = 'D:/3sxtra/build/application/bin/assets/stages/stage_14/shin_gouki_palette.bin'
with open(out_path, 'wb') as f:
    for val in final_palette:
        f.write(struct.pack('<H', val))

out_path_src = 'D:/3sxtra/assets/stages/stage_14/shin_gouki_palette.bin'
with open(out_path_src, 'wb') as f:
    for val in final_palette:
        f.write(struct.pack('<H', val))

print(f'Saved new shin_gouki_palette.bin directly into the build directory and assets dir.')
kept = sum(1 for i in range(1088) if final_palette[i] == orig[i])
print(f'Kept {kept} markers/shared-colors from the original AFS palette.')
